/*! wheels-basecoat-ui — small handlers that supplement basecoat-js. CSP-safe (no inline event handlers required when rendered with this script loaded). */
(function(){
"use strict";

// ----- Click-delegated handlers -----
document.addEventListener("click",function(e){
  // Dialog open / close (uiDialog).
  var t=e.target.closest("[data-ui-dialog-open]");
  if(t){var d=document.getElementById(t.getAttribute("data-ui-dialog-open"));if(d&&d.showModal)d.showModal();return;}
  var c=e.target.closest("[data-ui-dialog-close]");
  if(c){var dlg=c.closest("dialog");if(dlg)dlg.close();return;}
  if(e.target.tagName==="DIALOG"){e.target.close();return;}

  // Theme toggle (uiThemeToggle).
  var th=e.target.closest("[data-ui-theme-toggle]");
  if(th){var de=document.documentElement,n=de.classList.toggle("dark");try{localStorage.setItem(th.getAttribute("data-ui-theme-toggle")||"basecoat:theme",n?"dark":"light");}catch(_){}return;}

  // Sidebar toggle (uiSidebarToggle).
  var sb=e.target.closest("[data-ui-sidebar-toggle]");
  if(sb){var detail={action:sb.getAttribute("data-ui-sidebar-toggle")||"toggle"};var tid=sb.getAttribute("data-ui-sidebar-target");if(tid)detail.id=tid;document.dispatchEvent(new CustomEvent("basecoat:sidebar",{detail:detail}));return;}

  // Tag input pill remove.
  var tr=e.target.closest("[data-ui-tag-remove]");
  if(tr){var pill=tr.closest(".ui-tag-pill");if(pill){var ti=pill.closest(".ui-tag-input");pill.remove();syncTagInput(ti);}return;}

  // Code block copy.
  var cc=e.target.closest("[data-ui-code-copy]");
  if(cc){var pre=cc.closest(".ui-code-block").querySelector("pre code");if(pre){navigator.clipboard.writeText(pre.textContent).then(function(){cc.setAttribute("data-copied","");setTimeout(function(){cc.removeAttribute("data-copied");},1200);}).catch(function(){});}return;}
});

// ----- Slider live mirror (uiSlider) -----
function updateSlider(input){
  var min=parseFloat(input.min)||0,max=parseFloat(input.max)||100,val=parseFloat(input.value)||0;
  var pct=max===min?0:((val-min)/(max-min))*100;
  if(pct<0)pct=0;else if(pct>100)pct=100;
  input.style.setProperty("--slider-value",pct.toFixed(2)+"%");
  input.setAttribute("aria-valuenow",val);
  if(input.id){
    var out=document.querySelector('output[for="'+input.id+'"][data-ui-slider-output]');
    if(out)out.textContent=val;
  }
}
document.addEventListener("input",function(e){
  if(e.target.tagName==="INPUT"&&e.target.type==="range")updateSlider(e.target);
});

// ----- Tag input (uiTagInput) -----
function syncTagInput(ti){
  if(!ti)return;
  var name=ti.getAttribute("data-name")||"";
  var multiple=ti.getAttribute("data-multiple")==="true";
  var pills=ti.querySelectorAll(".ui-tag-pill");
  // Remove existing hidden inputs.
  ti.querySelectorAll(".ui-tag-input-hidden").forEach(function(h){h.remove();});
  if(multiple){
    pills.forEach(function(p){var h=document.createElement("input");h.type="hidden";h.className="ui-tag-input-hidden";h.name=name+"[]";h.value=p.getAttribute("data-value");ti.appendChild(h);});
  }else{
    var values=Array.from(pills).map(function(p){return p.getAttribute("data-value");}).join(",");
    var h=document.createElement("input");h.type="hidden";h.className="ui-tag-input-hidden";h.name=name;h.value=values;ti.appendChild(h);
  }
}
function addTag(ti,raw){
  var v=String(raw).trim();
  if(!v)return false;
  var maxTags=parseInt(ti.getAttribute("data-max-tags")||"0",10);
  var pills=ti.querySelectorAll(".ui-tag-pill");
  if(maxTags>0&&pills.length>=maxTags)return false;
  // Dedupe.
  for(var i=0;i<pills.length;i++){if(pills[i].getAttribute("data-value")===v)return false;}
  // Optional restriction to suggestions only.
  if(ti.getAttribute("data-allow-free")==="false"){
    var entry=ti.querySelector(".ui-tag-input-entry");
    var listId=entry&&entry.getAttribute("list");
    if(listId){
      var dl=document.getElementById(listId);
      var ok=false;
      if(dl){Array.from(dl.options).forEach(function(o){if(o.value===v)ok=true;});}
      if(!ok)return false;
    }
  }
  var pillsHost=ti.querySelector(".ui-tag-input-pills");
  var pill=document.createElement("span");
  pill.className="ui-tag-pill";
  pill.setAttribute("data-value",v);
  pill.innerHTML=v+' <button type="button" class="ui-tag-pill-remove" data-ui-tag-remove aria-label="Remove">×</button>';
  pillsHost.appendChild(pill);
  syncTagInput(ti);
  return true;
}
document.addEventListener("keydown",function(e){
  if(!e.target.classList||!e.target.classList.contains("ui-tag-input-entry"))return;
  var entry=e.target,ti=entry.closest(".ui-tag-input");
  if(!ti)return;
  if(e.key==="Enter"||e.key===","){
    if(entry.value.trim()){
      e.preventDefault();
      if(addTag(ti,entry.value))entry.value="";
    }
  }else if(e.key==="Backspace"&&!entry.value){
    var pills=ti.querySelectorAll(".ui-tag-pill");
    if(pills.length){pills[pills.length-1].remove();syncTagInput(ti);}
  }
});
document.addEventListener("change",function(e){
  // Datalist autocomplete: when the user picks an option from the datalist,
  // browsers fire change. Add as a tag immediately.
  if(!e.target.classList||!e.target.classList.contains("ui-tag-input-entry"))return;
  var entry=e.target,ti=entry.closest(".ui-tag-input");
  if(!ti||!entry.value.trim())return;
  if(addTag(ti,entry.value))entry.value="";
});

// ----- File upload drag-and-drop (uiFileUpload) -----
document.addEventListener("dragover",function(e){
  var fu=e.target.closest&&e.target.closest("[data-ui-file-upload]");
  if(!fu)return;
  e.preventDefault();fu.setAttribute("data-dragging","");
});
document.addEventListener("dragleave",function(e){
  var fu=e.target.closest&&e.target.closest("[data-ui-file-upload]");
  if(fu)fu.removeAttribute("data-dragging");
});
document.addEventListener("drop",function(e){
  var fu=e.target.closest&&e.target.closest("[data-ui-file-upload]");
  if(!fu)return;
  e.preventDefault();fu.removeAttribute("data-dragging");
  var input=fu.querySelector('input[type="file"]');
  if(input&&e.dataTransfer&&e.dataTransfer.files){
    input.files=e.dataTransfer.files;
    input.dispatchEvent(new Event("change",{bubbles:true}));
  }
});
document.addEventListener("change",function(e){
  if(e.target.tagName!=="INPUT"||e.target.type!=="file")return;
  var fu=e.target.closest("[data-ui-file-upload]");
  if(!fu)return;
  var list=fu.querySelector(".ui-file-upload-files");
  if(!list)return;
  list.innerHTML="";
  if(!e.target.files||!e.target.files.length){
    var d=document.createElement("p");d.className="ui-file-upload-files-empty";d.textContent="No files selected.";list.appendChild(d);
    return;
  }
  Array.from(e.target.files).forEach(function(f){
    var row=document.createElement("p");row.textContent=f.name+" ("+Math.round(f.size/1024)+" KB)";list.appendChild(row);
  });
});

})();
